    let fakeStats = {profit:0, wagered:0, wins:0, losses:0, profitHistory:[0]};

    function getStats() {
        const saved = localStorage.getItem(STATS_KEY);
        if (!saved) return {profit:0, wagered:0, wins:0, losses:0, profitHistory:[0]};
        try {
            const p = JSON.parse(saved);
            if (!Array.isArray(p.profitHistory)) p.profitHistory = [0];
            return {...{profit:0, wagered:0, wins:0, losses:0, profitHistory:[0]}, ...p};
        } catch(e) {
            return {profit:0, wagered:0, wins:0, losses:0, profitHistory:[0]};
        }
    }

    function saveStats() {
        localStorage.setItem(STATS_KEY, JSON.stringify(fakeStats));
    }

    function resetStats() {
        fakeStats = {profit:0, wagered:0, wins:0, losses:0, profitHistory:[0]};
        saveStats();
    }

    fakeStats = getStats();

    function drawGraph(svg, history) {
        if (!svg) return;
        if (!history || history.length < 2 || (history.length === 1 && history[0] === 0)) {
            svg.innerHTML = '';
            svg.setAttribute('width', 225);
            svg.setAttribute('height', 170);
            return;
        }
        svg.innerHTML = '';
        const w = 225, h = 170;
        const padX = 8, padTop = 8, padBottom = 8;
        const chartH = h - padTop - padBottom;
        const chartW = w - padX * 2;
        const max = Math.max(...history, 0);
        const min = Math.min(...history, 0);
        const range = (max - min) || 1;
        const toY = (val) => padTop + ((max - val) / range) * chartH;
        const toX = (idx) => padX + (idx / (history.length - 1)) * chartW;
        const zeroY = toY(0);
        const points = history.map((v, i) => ({ x: toX(i), y: toY(v) }));
        let pathD = `M ${points[0].x} ${points[0].y}`;
        if (points.length === 2) {
            pathD += ` L ${points[1].x} ${points[1].y}`;
        } else {
            for (let i = 0; i < points.length - 1; i++) {
                const p0 = points[Math.max(i - 1, 0)];
                const p1 = points[i];
                const p2 = points[i + 1];
                const p3 = points[Math.min(i + 2, points.length - 1)];
                const cp1x = p1.x + (p2.x - p0.x) / 6;
                const cp1y = p1.y + (p2.y - p0.y) / 6;
                const cp2x = p2.x - (p3.x - p1.x) / 6;
                const cp2y = p2.y - (p3.y - p1.y) / 6;
                pathD += ` C ${cp1x}, ${cp1y}, ${cp2x}, ${cp2y}, ${p2.x} ${p2.y}`;
            }
        }
        const last = points[points.length - 1];
        const first = points[0];
        const fillD = pathD + ` L ${last.x} ${zeroY} L ${first.x} ${zeroY}`;
        const positiveMaskH = Math.max(0, Math.min(zeroY, h));
        const negativeMaskY = Math.max(0, Math.min(zeroY, h));
        const negativeMaskH = h - negativeMaskY;
        svg.setAttribute('width', w);
        svg.setAttribute('height', h);
        svg.innerHTML = `
            <mask id="positiveMask"><rect x="0" y="0" fill="white" width="${w}" height="${positiveMaskH}"></rect></mask>
            <path fill="var(--color-green-500)" mask="url(#positiveMask)" fill-opacity="0.2" d="${fillD}"></path>
            <path fill="none" stroke="var(--color-green-500)" mask="url(#positiveMask)" stroke-width="2.5" d="${pathD}"></path>
            <mask id="negativeMask"><rect x="0" fill="white" y="${negativeMaskY}" width="${w}" height="${negativeMaskH}"></rect></mask>
            <path fill="var(--color-red-500)" mask="url(#negativeMask)" fill-opacity="0.2" d="${fillD}"></path>
            <path fill="none" stroke="var(--color-red-500)" mask="url(#negativeMask)" stroke-width="2.5" d="${pathD}"></path>
            <path stroke="grey" stroke-width="1" stroke-opacity="0.5" d="M ${padX} ${zeroY} L ${w - padX} ${zeroY}"></path>
        `;
    }

    function updateStatsDisplay() {
        const profitEl = document.querySelector('[data-testid="bets-stats-profit"]');
        if (!profitEl) return;
        const container = profitEl.closest('div.draggable');
        if (!container) return;
        const wageredEl = container.querySelector('[data-testid="bets-stats-wagered"]');
        const winsEl = container.querySelector('[data-testid="bets-stats-wins"]');
        const lossesEl = container.querySelector('[data-testid="bets-stats-losses"]');
        const svg = container.querySelector('div.graph-wrap svg');
        if (wageredEl && winsEl && lossesEl) {
            const fmt = (v) => v.toLocaleString('en-US', {style:'currency',currency:'USD'});
            profitEl.textContent = fmt(fakeStats.profit);
            profitEl.classList.remove('text-positive', 'text-critical');
            profitEl.classList.add(fakeStats.profit >= 0 ? 'text-positive' : 'text-critical');
            wageredEl.textContent = fmt(fakeStats.wagered);
            winsEl.textContent = fakeStats.wins.toString();
            lossesEl.textContent = fakeStats.losses.toString();
            if (svg) drawGraph(svg, fakeStats.profitHistory);
        }
    }

