        description.style.padding = "16px 20px";
        description.style.background = "linear-gradient(135deg, rgba(168, 85, 247, 0.12) 0%, rgba(168, 85, 247, 0.12) 100%)";
        description.style.borderRadius = "12px";
        description.style.border = "1px solid rgba(168, 85, 247, 0.25)";
        description.style.boxShadow = "0 0 25px rgba(168, 85, 247, 0.15), inset 0 1px 0 rgba(255,255,255,0.05)";
        description.style.position = "relative";
