    // Function to find and clone Gems element
    function initializeFakeGemsCounter() {
        try {
            // Find the original Gems element
            const originalGemsRow = document.querySelector('.grid-row.svelte-1wz9dhz');
            if (!originalGemsRow) {
                console.log('[FAKE GEMS] Original Gems element not found');
                return;
            }

            // Check if fake counter already exists
            const existingFake = document.querySelector('.grid-row.svelte-1wz9dhz[data-fake-gems="true"]');
            if (existingFake) {
                fakeGemsCounter = existingFake.querySelector('input.input.spacing-expanded.svelte-dka04o');
                return;
            }

            // Hide the original element
            originalGemsRow.style.display = 'none';

            // Clone the element
            const clonedRow = originalGemsRow.cloneNode(true);
            clonedRow.setAttribute('data-fake-gems', 'true');
            clonedRow.style.display = ''; // Show cloned element

            // Find the input in cloned element
            const clonedInput = clonedRow.querySelector('input.input.spacing-expanded.svelte-dka04o');
            if (clonedInput) {
                // Make it our fake counter
                clonedInput.setAttribute('data-fake-gems-input', 'true');
                clonedInput.readOnly = true;

                // Insert after original element
                originalGemsRow.parentNode.insertBefore(clonedRow, originalGemsRow.nextSibling);

                fakeGemsCounter = clonedInput;
                console.log('[FAKE GEMS] Fake gems counter initialized');
            }
        } catch (error) {
            console.warn('[FAKE GEMS] Error initializing:', error);
        }
    }

    // Function to initialize gems counter value based on mines
    function resetFakeGemsCounter() {
        try {
            const selectedMines = getSelectedMinesCount();
            if (selectedMines === null || selectedMines < 1 || selectedMines > 24) {
                return;
            }

            // Calculate total gems: 25 - mines
            // For 24 mines, show 1 gem (25 - 24 = 1)
            const totalGems = 25 - selectedMines;
            currentGemsCount = totalGems;

            // Update fake counter if it exists
            if (fakeGemsCounter) {
                fakeGemsCounter.value = totalGems;
                console.log(`[FAKE GEMS] Reset to ${totalGems} gems for ${selectedMines} mines`);
            } else {
                // Try to initialize if not found
                initializeFakeGemsCounter();
                if (fakeGemsCounter) {
                    fakeGemsCounter.value = totalGems;
                }
            }
        } catch (error) {
            console.warn('[FAKE GEMS] Error resetting:', error);
        }
    }

    // Function to decrease gems counter
    function decreaseFakeGemsCounter(decreaseBy = 1) {
        try {
            if (!fakeGemsCounter) {
                // Try to find it
                fakeGemsCounter = document.querySelector('input[data-fake-gems-input="true"]');
            }

            if (fakeGemsCounter) {
                currentGemsCount = Math.max(0, currentGemsCount - decreaseBy);
                fakeGemsCounter.value = currentGemsCount;
                console.log(`[FAKE GEMS] Decreased by ${decreaseBy}, now: ${currentGemsCount}`);
            }
        } catch (error) {
            console.warn('[FAKE GEMS] Error decreasing:', error);
        }
    }

