    function getMultiplierForDiamonds(config, diamondsRevealed) {
        if (!config || !Array.isArray(config.multipliers)) {
            return DEFAULT_MINE_CONFIG.multipliers[0].multiplier;
        }
        const exactMatch = config.multipliers.find(entry => entry.diamonds === diamondsRevealed);
        if (exactMatch) return exactMatch.multiplier;
        const fallback = config.multipliers[config.multipliers.length - 1];
        return fallback ? fallback.multiplier : DEFAULT_MINE_CONFIG.multipliers[0].multiplier;
    }

    function pickTilesForReplacement(allTiles, primaryTile, required) {
        const tilesNeeded = Math.max(1, required || 1);
        const selected = new Set();

        // Add primary tile if it's not already revealed
        if (primaryTile && primaryTile.getAttribute('data-revealed') !== 'true') {
            selected.add(primaryTile);
        }

        // Add other tiles, excluding already revealed ones
        for (const tile of allTiles) {
            if (selected.size >= tilesNeeded) break;
            if (tile === primaryTile) continue;
            // Skip already revealed tiles (gems)
            if (tile.getAttribute('data-revealed') === 'true') continue;
            selected.add(tile);
        }
        return selected;
    }

    function replaceTileWithType(tile, type, isClickedBomb = false) {
        if (!tile) return null;
        const template = document.createElement('template');
        if (type === 'gem') {
            template.innerHTML = gemHTML.trim();
        } else if (type === 'bomb') {
            // Use clickedBombHTML if it's the clicked bomb (with GIF), otherwise use bombHTML
            template.innerHTML = isClickedBomb ? clickedBombHTML.trim() : bombHTML.trim();
        } else {
            template.innerHTML = normalHTML.trim();
        }
        const newNode = template.content.firstElementChild;
        if (!newNode) return null;
        tile.replaceWith(newNode);
        return newNode;
    }

    function triggerTileReplacement(allTiles, tilesToHighlight, clickedTile) {
        let newClickedNode = null;
        allTiles.forEach(tile => {
            // Skip already revealed tiles (gems) - don't replace them
            if (tile.getAttribute('data-revealed') === 'true') {
                return;
            }

            const shouldHighlight = tilesToHighlight.has(tile);
            const newNode = replaceTileWithType(tile, shouldHighlight ? 'gem' : 'bomb');
            if (shouldHighlight && tile === clickedTile) {
                newClickedNode = newNode;
            }
        });
        return newClickedNode;
    }

