    // Unified button state monitoring - ensures consistent behavior
    function startButtonStateMonitoring() {
        if (buttonStateInterval) {
            clearInterval(buttonStateInterval);
        }

        buttonStateInterval = setInterval(() => {
            if (!foundButtons) return;

            const { half, double } = foundButtons;

            // Check if bet is active using multiple indicators
            const minesSelect = document.querySelector(SELECT_SELECTOR);
            const isBetActive = minesSelect && minesSelect.disabled;
            const isBodyBetActive = document.body.classList.contains('bet-active');
            const isWrapperBetActive = document.querySelector('.input-button-wrap.svelte-dka04o')?.classList.contains('bet-active');

            const shouldDisable = isBetActive || isBodyBetActive || isWrapperBetActive;

            if (shouldDisable) {
                // Disable buttons when bet is active
                disableButton(half);
                disableButton(double);
                setBetTabButtonsDisabled(true);
            } else {
                // Enable buttons when no bet is active
                enableButton(half);
                enableButton(double);
                setBetTabButtonsDisabled(false);
            }
        }, 100); // Check every 100ms
    }

    function setBetTabButtonsDisabled(disabled) {
        const tabButtons = [
            ...document.querySelectorAll('button[data-testid="manual-tab"]'),
            ...document.querySelectorAll('button[data-testid="auto-tab"]')
        ];

        tabButtons.forEach((btn) => {
            btn.disabled = disabled;
            if (disabled) {
                btn.setAttribute('disabled', 'true');
                btn.setAttribute('data-bet-disabled', 'true');
                btn.style.opacity = '0.5';
                btn.style.pointerEvents = 'none';
                btn.style.cursor = 'not-allowed';
            } else {
                btn.removeAttribute('disabled');
                btn.removeAttribute('data-bet-disabled');
                btn.style.opacity = '1';
                btn.style.pointerEvents = 'auto';
                btn.style.cursor = 'pointer';
            }
        });
    }

    function disableButton(btn) {
        const halfSelector = 'button[data-testid="amount-halve"]';
        const doubleSelector = 'button[data-testid="amount-double"]';
        const text = (btn?.textContent || '').trim();
        const isHalf = btn?.getAttribute('data-testid') === 'amount-halve' || text === '½' || text === '1/2';
        const isDouble = btn?.getAttribute('data-testid') === 'amount-double' || text === '2\u00D7' || text === '2x';
        const targets = new Set();

        if (isHalf) {
            document.querySelectorAll(halfSelector).forEach(b => targets.add(b));
            document.querySelectorAll('button').forEach(b => {
                const t = b.textContent.trim();
                if (t === '½' || t === '1/2') targets.add(b);
            });
        }

        if (isDouble) {
            document.querySelectorAll(doubleSelector).forEach(b => targets.add(b));
            document.querySelectorAll('button').forEach(b => {
                const t = b.textContent.trim();
                if (t === '2\u00D7' || t === '2x') targets.add(b);
            });
        }

        if (btn) targets.add(btn);
        if (targets.size === 0) return;

        targets.forEach(target => {
            target.disabled = true;
            target.setAttribute('disabled', 'true');
            target.style.opacity = '0.5';
            target.style.pointerEvents = 'none';
            target.style.cursor = 'not-allowed';
            target.setAttribute('data-bet-disabled', 'true');
        });
    }

    function enableButton(btn) {
        const halfSelector = 'button[data-testid="amount-halve"]';
        const doubleSelector = 'button[data-testid="amount-double"]';
        const text = (btn?.textContent || '').trim();
        const isHalf = btn?.getAttribute('data-testid') === 'amount-halve' || text === '½' || text === '1/2';
        const isDouble = btn?.getAttribute('data-testid') === 'amount-double' || text === '2\u00D7' || text === '2x';
        const targets = new Set();

        if (isHalf) {
            document.querySelectorAll(halfSelector).forEach(b => targets.add(b));
            document.querySelectorAll('button').forEach(b => {
                const t = b.textContent.trim();
                if (t === '½' || t === '1/2') targets.add(b);
            });
        }

        if (isDouble) {
            document.querySelectorAll(doubleSelector).forEach(b => targets.add(b));
            document.querySelectorAll('button').forEach(b => {
                const t = b.textContent.trim();
                if (t === '2\u00D7' || t === '2x') targets.add(b);
            });
        }

        if (btn) targets.add(btn);
        if (targets.size === 0) return;

        targets.forEach(target => {
            target.disabled = false;
            target.removeAttribute('disabled');
            target.style.opacity = '1';
            target.style.pointerEvents = 'auto';
            target.style.cursor = 'pointer';
            target.removeAttribute('data-bet-disabled');
        });
    }

